import strings from "../data/strings.json" with {type: "json"}

export default {
    /**
     * Returns a collection based on selected language 
     * 
     * (note: these collections are generated on langToCollections() function) 
     * @param {Object} Object containing language to translate and collections generated by eleventy  
     * @returns empty {} or collection
     */
    getTranslatedCollection({ language, collections }) {
        if (language === undefined) {
            return "No language"
        }
        switch (language) {
            case "english":
                return collections.en
            case "spanish":
                return collections.es
            default:
                return "no collection"
        }
    },
    /**
     * Returns strings.json based on language 
     * 
     * @param {Object} Object containing language to translate and collections generated by eleventy  
     * @returns empty {} or collection
     */
    getTranslatedStrings({ language }) {
        
        if (language === undefined) {
            return {}
        }
        switch (language) {
            case "english":
                return strings.en
            case "spanish":
                return strings.es
            default:
                return {}
        }
    }
}